    tags: ['Traditional', 'Cake'],
    youtube: null,
    ingredients: [
      { name: { en: 'Flour', ro: 'faina', ru: 'мука', es: 'harina' }, measure: '300g' },
      { name: { en: 'Sugar', ro: 'zahar', ru: 'сахар', es: 'azucar' }, measure: '200g' },
      { name: { en: 'Eggs', ro: 'oua', ru: 'яйца', es: 'huevos' }, measure: '5' },
      { name: { en: 'Butter', ro: 'unt', ru: 'сливочное масло', es: 'mantequilla' }, measure: '200g' },
      { name: { en: 'Cocoa Powder', ro: 'cacao', ru: 'какао', es: 'cacao en polvo' }, measure: '50g' },
      { name: { en: 'Baking Soda', ro: 'bicarbonat de sodiu', ru: 'сода', es: 'bicarbonato de sodio' }, measure: '1 teaspoon' },
      { name: { en: 'Vinegar', ro: 'otet', ru: 'уксус', es: 'vinagre' }, measure: '1 tablespoon' },
      { name: { en: 'Apricot Jam', ro: 'gem de caise', ru: 'абрикосовое варенье', es: 'mermelada de albaricoque' }, measure: '4 tablespoons' },
      { name: { en: 'Milk', ro: 'lapte', ru: 'молоко', es: 'leche' }, measure: '200ml' },
      { name: { en: 'Vanilla Extract', ro: 'extract de vanilie', ru: 'ванильный экстракт', es: 'extracto de vainilla' }, measure: '1 teaspoon' },
    ],
